import React, { useState } from 'react';
import { NavLink, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
// import Logo from './Logo';

function initials(name = '') {
  return name.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);
}

export default function Layout({ children }) {
  const { user, logout, isHR } = useAuth();
  const navigate  = useNavigate();
  const location  = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleLogout = () => { logout(); navigate('/login'); };
  const closeSidebar = () => setSidebarOpen(false);

  const hrNav = [
    { to: '/',            icon: '📊', label: 'Dashboard'  },
    { to: '/applicants',  icon: '👥', label: 'Applicants' },
    { to: '/pipeline',    icon: '🔄', label: 'Pipeline'   },
    { to: '/interviews',  icon: '📅', label: 'Interviews' },
    { to: '/ai-ranking',  icon: '🏆', label: 'AI Ranking' },
    { to: '/analytics',   icon: '📈', label: 'Analytics'  },
  ];

  const candidateNav = [
    { to: '/jobs',            icon: '💼', label: 'Browse Jobs'     },
    { to: '/my-applications', icon: '📋', label: 'My Applications' },
  ];

  const nav = isHR ? hrNav : candidateNav;

  const SidebarContent = () => (
    <>
      <div className="sidebar-logo">
        <Logo size={34} textSize="md" />
        <button
          onClick={closeSidebar}
          className="sidebar-close-btn"
          aria-label="Close menu"
        >
          ✕
        </button>
      </div>

      <div className="nav-section">Navigation</div>
      {nav.map((item) => (
        <NavLink
          key={item.to}
          to={item.to}
          end={item.to === '/'}
          className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}
          onClick={closeSidebar}
        >
          <span className="nav-icon">{item.icon}</span>
          {item.label}
        </NavLink>
      ))}

      {isHR && (
        <>
          <div className="nav-section">Jobs</div>
          <NavLink
            to="/jobs"
            className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}
            onClick={closeSidebar}
          >
            <span className="nav-icon">💼</span>All Vacancies
          </NavLink>
          <NavLink
            to="/post-job"
            className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}
            onClick={closeSidebar}
          >
            <span className="nav-icon">➕</span>Post a Job
          </NavLink>
        </>
      )}

      <div className="sidebar-footer">
        <div className="user-row" onClick={handleLogout} title="Click to logout">
          <div className="avatar" style={{ width: 34, height: 34, fontSize: 12 }}>
            {initials(user?.name)}
          </div>
          <div>
            <div style={{ color: '#fff', fontSize: 13, fontWeight: 500 }}>{user?.name}</div>
            <div style={{ color: 'var(--gray400)', fontSize: 11 }}>
              {user?.role?.replace('_', ' ')} · Logout
            </div>
          </div>
        </div>
      </div>
    </>
  );

  return (
    <>
      {/* Mobile backdrop */}
      {sidebarOpen && (
        <div className="sidebar-backdrop" onClick={closeSidebar} />
      )}

      <div className="app-shell">
        {/* Desktop sidebar */}
        <aside className="sidebar sidebar-desktop">
          <SidebarContent />
        </aside>

        {/* Mobile drawer sidebar */}
        <aside className={`sidebar sidebar-mobile${sidebarOpen ? ' open' : ''}`}>
          <SidebarContent />
        </aside>

        {/* Main content */}
        <div className="main-area">
          <header className="topbar">
            <button
              className="hamburger-btn"
              onClick={() => setSidebarOpen(true)}
              aria-label="Open navigation menu"
            >
              <span />
              <span />
              <span />
            </button>

            <div className="topbar-title">{getPageTitle(location.pathname)}</div>

            {isHR ? (
              <button className="btn btn-primary btn-sm" onClick={() => navigate('/post-job')}>
                + Post Job
              </button>
            ) : (
              <button className="btn btn-primary btn-sm" onClick={() => navigate('/jobs')}>
                Browse Jobs
              </button>
            )}
          </header>

          <main className="page-content page-fade">{children}</main>
        </div>
      </div>

      <style>{`
        /* ── Hamburger button ──────────────────────── */
        .hamburger-btn {
          display: none;
          flex-direction: column;
          justify-content: space-between;
          width: 24px;
          height: 18px;
          background: none;
          border: none;
          cursor: pointer;
          padding: 0;
          flex-shrink: 0;
          margin-right: 14px;
        }
        .hamburger-btn span {
          display: block;
          width: 100%;
          height: 2px;
          background: var(--gray600);
          border-radius: 2px;
        }

        /* ── Sidebar close button ─────────────────── */
        .sidebar-close-btn {
          display: none;
          margin-left: auto;
          background: none;
          border: none;
          color: var(--gray400);
          font-size: 20px;
          cursor: pointer;
          padding: 4px 8px;
          border-radius: 6px;
          line-height: 1;
        }
        .sidebar-close-btn:hover { background: rgba(255,255,255,0.1); color: #fff; }

        /* ── Desktop: show sidebar normally ──────── */
        .sidebar-desktop { display: flex; flex-direction: column; }
        .sidebar-mobile  {
          display: flex;
          flex-direction: column;
          position: fixed;
          top: 0; left: 0;
          height: 100vh;
          width: 240px;
          z-index: 50;
          transform: translateX(-100%);
          transition: transform 0.25s cubic-bezier(0.4,0,0.2,1);
          box-shadow: 4px 0 24px rgba(0,0,0,0.3);
        }
        .sidebar-mobile.open { transform: translateX(0); }

        /* ── Backdrop ─────────────────────────────── */
        .sidebar-backdrop {
          display: none;
          position: fixed;
          inset: 0;
          background: rgba(0,0,0,0.55);
          z-index: 40;
          backdrop-filter: blur(2px);
        }

        /* ── Mobile breakpoint ────────────────────── */
        @media (max-width: 768px) {
          .hamburger-btn     { display: flex; }
          .sidebar-desktop   { display: none !important; }
          .sidebar-backdrop  { display: block; }
          .sidebar-close-btn { display: block; }

          .topbar       { padding: 0 16px; gap: 0; }
          .page-content { padding: 16px; }

          .grid-4 { grid-template-columns: 1fr 1fr !important; }
          .grid-3 { grid-template-columns: 1fr 1fr !important; }
          .kanban { grid-template-columns: 1fr !important; }

          .table-wrap table th:nth-child(4),
          .table-wrap table td:nth-child(4),
          .table-wrap table th:nth-child(5),
          .table-wrap table td:nth-child(5) {
            display: none;
          }
        }

        /* ── Small mobile ─────────────────────────── */
        @media (max-width: 480px) {
          .grid-4 { grid-template-columns: 1fr !important; }
          .grid-3 { grid-template-columns: 1fr !important; }
          .grid-2 { grid-template-columns: 1fr !important; }
          .form-row { grid-template-columns: 1fr !important; }

          .stat-value    { font-size: 22px !important; }
          .topbar-title  { font-size: 14px; }
          .page-content  { padding: 12px; }

          .btn-sm { padding: 5px 8px; font-size: 11px; }
        }
      `}</style>
    </>
  );
}

function getPageTitle(path) {
  const map = {
    '/':                'Dashboard',
    '/jobs':            'Job Vacancies',
    '/post-job':        'Post New Job',
    '/applicants':      'Applicants',
    '/pipeline':        'Hiring Pipeline',
    '/interviews':      'Interviews',
    '/ai-ranking':      'AI Candidate Ranking',
    '/analytics':       'Analytics',
    '/my-applications': 'My Applications',
  };
  return map[path] || 'TalentOS';
}
